class Solution:
    def smallestBalancedIndex(self, nums):
        # independent construction: build both prefix sums and suffix products as separate
        # arrays first (rather than folding sum/product into one combined pass), then compare.
        n = len(nums)
        CAP = 2 * 10**14
        prefix_sums = [0] * n
        running = 0
        for i in range(n):
            prefix_sums[i] = running
            running += nums[i]
        suffix_products = [1] * n
        running_p = 1
        for i in range(n - 2, -1, -1):
            running_p = running_p * nums[i + 1]
            if running_p > CAP:
                running_p = CAP + 1
            suffix_products[i] = running_p
        for i in range(n):
            if prefix_sums[i] == suffix_products[i]:
                return i
        return -1

