class Solution:
    def smallestBalancedIndex(self, nums):
        n = len(nums)
        CAP = 2 * 10**14
        right = [0] * n
        right[n - 1] = 1
        for i in range(n - 2, -1, -1):
            prod = right[i + 1] * nums[i + 1]
            right[i] = CAP + 1 if prod > CAP else prod
        prefix = 0
        for i in range(n):
            if prefix == right[i]:
                return i
            prefix += nums[i]
        return -1

