var smallestBalancedIndex = function(nums) {
    const n = nums.length;
    const CAP = 2e14;
    const right = new Array(n);
    right[n - 1] = 1;
    for (let i = n - 2; i >= 0; i--) {
        const prod = right[i + 1] * nums[i + 1];
        right[i] = prod > CAP ? CAP + 1 : prod;
    }
    let prefix = 0;
    for (let i = 0; i < n; i++) {
        if (prefix === right[i]) return i;
        prefix += nums[i];
    }
    return -1;
};
